import constFlaskURL from "../consts/constFlaskURL";
import { useCallback } from "react";


export const useFetchTableData = () => { 
    const fetchTableData = useCallback(async (url = '/roads') => {
        try {
            const response = await constFlaskURL.get(url);

            if (response.status === 200) {
                return Array.isArray(response.data) ? response.data : [response.data];
            }
        } catch (err) {
            console.log(err);
            throw err;
        } 
    }, []);

    console.log('Returning:', typeof fetchTableData); 
    return fetchTableData;
}
